function WeddingPhotography() {
    const photographers = [
        {
            name: "Royal Lens Studio",
            experience: "7 Years",
            service: "Full Wedding Photography",
            package:
                "Bride and groom photoshoot, ceremony coverage, reception photos, and edited digital album.",
            contact: "RoyalLens@email.com",
            price: "$600 package",
            image: "https://cdn-icons-png.flaticon.com/512/2922/2922510.png",
        },
        {
            name: "Diamond Capture",
            experience: "5 Years",
            service: "Engagement and Wedding Photos",
            package:
                "Engagement session, wedding day highlights, couple portraits, and online photo gallery.",
            contact: "Diamondcapture@email.com",
            price: "$700package",
            image: "https://cdn-icons-png.flaticon.com/512/3004/3004613.png",
        },
        {
            name: "Velvet Memories",
            experience: "8 Years",
            service: "Luxury Wedding Photography",
            package:
                "Full-day photography, cinematic shots, premium editing, printed album, and USB delivery.",
            contact: "royalmemories@email.com",
            price: "$800 package",
            image: "https://cdn-icons-png.flaticon.com/512/1042/1042339.png",
        },
    ];

    function requestPhotographer(name) {
        alert("Your request has been sent to " + name);
    }

    return (
        <section className="page-section">
            <div className="page-header">
                <h1>Wedding Photography</h1>

                <p>
                    Find professional photographers to capture your wedding memories with
                    beautiful and high-quality photos.
                </p>
            </div>

            <section className="cards">
                {photographers.map((photographer, index) => (
                    <div className="card" key={index}>
                        <img
                            src={photographer.image}
                            alt={photographer.name}
                            className="service-image"
                        />

                        <h3>{photographer.name}</h3>

                        <p><strong>Service:</strong> {photographer.service}</p>
                        <p><strong>Package Includes:</strong> {photographer.package}</p>
                        <p><strong>Experience:</strong> {photographer.experience}</p>
                        <p><strong>Email:</strong> {photographer.contact}</p>
                        <p><strong>Price:</strong> {photographer.price}</p>

                        <button
                            className="request-btn"
                            onClick={() => requestPhotographer(photographer.name)}
                        >
                            Request Service
                        </button>
                    </div>
                ))}
            </section>
        </section>
    );
}

export default WeddingPhotography;
